  -H "Authorization: Bearer $HOOKDECK_API_KEY" \
  -H "Content-Type: application/json" \
  -d '{
    "name": "validate-zr-jcw37bg",
    "code": "function transform(request) {
  var body = request.body;

  if (typeof body.user_id !== "string" || body.user_id === "") {
    console.log("validation_failed user_id");
    return null;
  }

  if (typeof body.amount !== "number" || !isFinite(body.amount)) {
    console.log("validation_failed amount");
    return null;
  }

  return request;
}"
